if (ctx.containsKey('agent') && ctx.agent != null) {
  if (!ctx.containsKey('host') || ctx.host == null) {
    ctx['host'] = new HashMap();
  }
  Map agent = ctx.agent;
  Map host = ctx.host;
  if (agent.containsKey('id') && (!host.containsKey('id') || host['id'] == null)) {
    host['id'] = agent['id'];
  }
  if (!host.containsKey('name') || host['name'] == null) {
    if (agent.containsKey('name') && agent['name'] != null) {
      host['name'] = agent['name'];
    } else if (agent.containsKey('hostname') && agent['hostname'] != null) {
      host['name'] = agent['hostname'];
    }
  }
}
if (!ctx.containsKey('m_26_14') || ctx.m_26_14 == null) {
  ctx['m_26_14'] = new HashMap();
}
ctx['m_26_14']['managed'] = true;
ctx['m_26_14']['hwam_source'] = 'osquery';

if (!ctx.containsKey('package') || ctx.package == null) return;
Map pkg = ctx.package;
if (!ctx.containsKey('m_26_14') || ctx.m_26_14 == null) return;
Map m_26_14 = ctx.m_26_14;
if (!m_26_14.containsKey('software') || m_26_14.software == null) return;
Map sw = m_26_14.software;
// Promote publisher: catalog enrichment wins if present, otherwise keep existing
if (sw.containsKey('publisher') && sw.publisher != null && !pkg.containsKey('publisher')) {
  pkg['publisher'] = sw.publisher;
}
// Promote category: catalog enrichment wins; normalize to lowercase
if (sw.containsKey('category') && sw.category != null && !pkg.containsKey('category')) {
  pkg['category'] = sw.category.toString().toLowerCase();
}

if (!ctx.containsKey('asset') || ctx.asset == null) {
  ctx['asset'] = new HashMap();
}
Map asset = ctx.asset;

// asset.name + source + managed
if (ctx?.host?.name != null && !asset.containsKey('name')) {
  asset['name'] = ctx.host.name;
}
asset['source'] = 'osquery';
asset['managed'] = true;
asset['last_seen'] = ctx['@timestamp'];

// asset.hardware.* from m_26_14.hardware.*
if (ctx.containsKey('m_26_14') && ctx.m_26_14 != null && ctx.m_26_14.containsKey('hardware') && ctx.m_26_14.hardware != null) {
  Map hw = ctx.m_26_14.hardware;
  Map assetHw = new HashMap();
  if (hw.containsKey('vendor') && hw.vendor != null)            assetHw['manufacturer']     = hw.vendor;
  if (hw.containsKey('model') && hw.model != null)              assetHw['model']            = hw.model;
  if (hw.containsKey('serial') && hw.serial != null)            assetHw['serial_number']    = hw.serial;
  if (hw.containsKey('board_vendor') && hw.board_vendor != null) assetHw['bios_manufacturer'] = hw.board_vendor;
  if (hw.containsKey('board_model') && hw.board_model != null)  assetHw['bios_version']     = hw.board_model;
  if (hw.containsKey('cpu_brand') && hw.cpu_brand != null) {
    Map cpu = new HashMap();
    cpu['brand'] = hw.cpu_brand;
    if (hw.containsKey('cpu_cores_physical') && hw.cpu_cores_physical != null) cpu['cores_physical'] = hw.cpu_cores_physical;
    if (hw.containsKey('cpu_cores_logical') && hw.cpu_cores_logical != null)   cpu['cores_logical']  = hw.cpu_cores_logical;
    assetHw['cpu'] = cpu;
  }
  if (hw.containsKey('memory_bytes') && hw.memory_bytes != null) assetHw['memory_bytes'] = hw.memory_bytes;
  if (assetHw.size() > 0) asset['hardware'] = assetHw;
}

// asset.os.* from host.os.*
if (ctx.containsKey('host') && ctx.host != null && ctx.host.containsKey('os') && ctx.host.os != null) {
  Map os = ctx.host.os;
  Map assetOs = new HashMap();
  if (os.containsKey('name') && os.name != null)     assetOs['name']    = os.name;
  if (os.containsKey('version') && os.version != null) assetOs['version'] = os.version;
  if (os.containsKey('platform') && os.platform != null) {
    assetOs['platform'] = os.platform.toLowerCase();
  } else if (os.containsKey('family') && os.family != null) {
    assetOs['platform'] = os.family.toLowerCase();
  }
  if (os.containsKey('arch') && os.arch != null) assetOs['architecture'] = os.arch;
  // os.build (osquery exposes this as os_version.build or host.os.build)
  if (os.containsKey('build') && os.build != null)   assetOs['build'] = os.build;
  if (os.containsKey('eol') && os.eol != null)       assetOs['eol']   = os.eol;
  if (assetOs.size() > 0) asset['os'] = assetOs;
}

Set junkSerials = new HashSet(['', '0', 'default string', 'to be filled by o.e.m.', 'system serial number', 'none', 'not specified', 'o.e.m.', 'na', 'n/a']);
String keyType = null;
String rawKey = null;

// 1. Hardware serial
String serial = null;
if (ctx.containsKey('asset') && ctx.asset != null && ctx.asset.containsKey('hardware') && ctx.asset.hardware != null) {
  serial = ctx.asset.hardware.get('serial_number');
}
if (serial == null && ctx.containsKey('m_26_14') && ctx.m_26_14 != null && ctx.m_26_14.containsKey('hardware') && ctx.m_26_14.hardware != null) {
  serial = ctx.m_26_14.hardware.get('serial');
}
if (serial != null && serial.length() > 0 && !junkSerials.contains(serial.toLowerCase())) {
  keyType = 'serial';
  rawKey = serial.toLowerCase();
}

// 2. Elastic agent ID
if (keyType == null && ctx.containsKey('agent') && ctx.agent != null && ctx.agent.containsKey('id') && ctx.agent.id != null) {
  keyType = 'agent';
  rawKey = ctx.agent.id;
}

// 3. First MAC address
if (keyType == null) {
  String mac = null;
  if (ctx.containsKey('host') && ctx.host != null && ctx.host.containsKey('mac')) {
    def macField = ctx.host.mac;
    if (macField instanceof List) {
      if (macField.size() > 0) mac = (String)macField[0];
    } else if (macField instanceof String) {
      mac = macField;
    }
  }
  if (mac != null && mac.length() > 0) {
    keyType = 'mac';
    rawKey = mac.toLowerCase().replace('-', ':');
  }
}

// 4. Hostname fallback
if (keyType == null && ctx.containsKey('host') && ctx.host != null && ctx.host.containsKey('name') && ctx.host.name != null) {
  keyType = 'hostname';
  rawKey = ctx.host.name.toLowerCase();
}

// Store resolution key for fingerprint processor; record confidence
if (keyType != null) {
  ctx['_asset_resolution_key'] = keyType + ':' + rawKey;
  Map confidenceMap = new HashMap();
  confidenceMap.put('serial', 0.95);
  confidenceMap.put('agent', 0.85);
  confidenceMap.put('mac', 0.70);
  confidenceMap.put('hostname', 0.40);
  if (!ctx.containsKey('asset') || ctx.asset == null) ctx['asset'] = new HashMap();
  ctx.asset['_resolution_type'] = keyType;
  ctx.asset['_resolution_confidence'] = confidenceMap.get(keyType);
}
